content:
{
  "sentences": [
    {
      "text": "你穿什麼尺寸的衣服？",
      "pinyin": "Nǐ chuān shénme chǐcùn de yīfu?",
      "pinyin_numeric": "ni3 chuan1 shen2me chi3cun4 de5 yi1fu5",
      "translation_en": "What size clothes do you wear?",
      "translation_ko": "무슨 사이즈 옷을 입으세요?"
    },
    {
      "text": "我穿中號的上衣，可是褲子穿大號。",
      "pinyin": "Wǒ chuān zhōng hào de shàngyī, kěshì kùzi chuān dà hào.",
      "pinyin_numeric": "wo3 chuan1 zhong1 hao4 de5 shang4yi1, ke3shi4 ku4zi chuan1 da4 hao4.",
      "translation_en": "I wear a medium top, but I wear large pants.",
      "translation_ko": "저는 상의는 중간 사이즈를 입는데, 바지는 큰 사이즈를 입어요."
    },
    {
      "text": "這件外套有黑色的嗎？",
      "pinyin": "Zhè jiàn wàitào yǒu hēisè de ma?",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 you3 hei1se4 de5 ma0",
      "translation_en": "Does this jacket come in black?",
      "translation_ko": "이 외투는 검은색이 있나요?"
    },
    {
      "text": "我想試穿這件藍色的裙子，可以嗎？",
      "pinyin": "Wǒ xiǎng shìchuān zhè jiàn lánsè de qúnzi, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 shi4chuan1 zhe4 jian4 lan2se4 de5 qun2zi, ke3yi3 ma0",
      "translation_en": "I want to try on this blue skirt, is that okay?",
      "translation_ko": "이 파란색 치마를 입어 봐도 될까요?"
    },
    {
      "text": "這雙鞋子太小了，有大一點的嗎？",
      "pinyin": "Zhè shuāng xiézi tài xiǎo le, yǒu dà yīdiǎn de ma?",
      "pinyin_numeric": "zhe4 shuang1 xie2zi tai4 xiao3 le5, you3 da4 yi1dian3 de5 ma0",
      "translation_en": "These shoes are too small; do you have a bigger size?",
      "translation_ko": "이 신발은 너무 작은데, 더 큰 사이즈가 있나요?"
    },
    {
      "text": "這件褲子穿起來很舒服，可是顏色不適合我。",
      "pinyin": "Zhè jiàn kùzi chuān qǐlái hěn shūfu, kěshì yánsè bù shìhé wǒ.",
      "pinyin_numeric": "zhe4 jian4 ku4zi chuan1 qi3lai2 hen3 shu1fu5, ke3shi4 yan2se4 bu4 shi4he2 wo3.",
      "translation_en": "These pants feel very comfortable, but the color doesn't suit me.",
      "translation_ko": "이 바지는 입었을 때 편안한데, 색상이 저한테 안 어울려요."
    },
    {
      "text": "這件上衣有打折嗎？原價多少錢？",
      "pinyin": "Zhè jiàn shàngyī yǒu dǎzhé ma? Yuánjià duōshao qián?",
      "pinyin_numeric": "zhe4 jian4 shang4yi1 you3 da3zhe2 ma0? yuan2jia4 duo1shao qian2?",
      "translation_en": "Is this top on sale? What's the original price?",
      "translation_ko": "이 상의는 할인하나요? 원래 가격이 얼마인가요?"
    },
    {
      "text": "我穿小號的褲子，可是這件褲子太大了。",
      "pinyin": "Wǒ chuān xiǎo hào de kùzi, kěshì zhè jiàn kùzi tài dà le.",
      "pinyin_numeric": "wo3 chuan1 xiao3 hao4 de5 ku4zi, ke3shi4 zhe4 jian4 ku4zi tai4 da4 le5.",
      "translation_en": "I wear small pants, but these pants are too big.",
      "translation_ko": "저는 바지를 작은 사이즈로 입는데, 이 바지는 너무 커요."
    },
    {
      "text": "試衣間在哪裡？我想試穿這件外套。",
      "pinyin": "Shìyījiān zài nǎlǐ? Wǒ xiǎng shìchuān zhè jiàn wàitào.",
      "pinyin_numeric": "shi4yi1jian1 zai4 na3li3? wo3 xiang3 shi4chuan1 zhe4 jian4 wai4tao4.",
      "translation_en": "Where is the fitting room? I want to try on this jacket.",
      "translation_ko": "탈의실이 어디에 있나요? 이 외투를 입어 보고 싶어요."
    },
    {
      "text": "這件裙子有白色的嗎？我想買一件。",
      "pinyin": "Zhè jiàn qúnzi yǒu báisè de ma? Wǒ xiǎng mǎi yī jiàn.",
      "pinyin_numeric": "zhe4 jian4 qun2zi you3 bai2se4 de5 ma0? wo3 xiang3 mai3 yi1 jian4.",
      "translation_en": "Does this skirt come in white? I want to buy one.",
      "translation_ko": "이 치마는 흰색이 있나요? 하나 사고 싶어요."
    }
  ]
}
